"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[6287],{4964(e,n,t){t.r(n),t.d(n,{assets:()=>r,contentTitle:()=>a,default:()=>c,frontMatter:()=>s,metadata:()=>h,toc:()=>d});var o=t(4848),i=t(8453);const s={},a="Chapter 17: Grey Rock Mode",h={id:"mirror-realm/ch17",title:"Chapter 17: Grey Rock Mode",description:"Taiwan Edition v2",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/ch17.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/ch17",permalink:"/MythogenEngine/en/docs/mirror-realm/ch17",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 16: Whispers in the KTV Room",permalink:"/MythogenEngine/en/docs/mirror-realm/ch16"},next:{title:"Chapter 18: The Final Refusal",permalink:"/MythogenEngine/en/docs/mirror-realm/ch18"}},r={},d=[{value:"Taiwan Edition v2",id:"taiwan-edition-v2",level:2}];function l(e){const n={blockquote:"blockquote",em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.header,{children:(0,o.jsx)(n.h1,{id:"chapter-17-grey-rock-mode",children:"Chapter 17: Grey Rock Mode"})}),"\n",(0,o.jsx)(n.h2,{id:"taiwan-edition-v2",children:"Taiwan Edition v2"}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"Location: The Mirror Realm\u30fbJade Mirror Island\nTime: August\u2014October, 1024\nProtagonist: Lin Zhaoming"}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"Study room."}),"\n",(0,o.jsx)(n.p,{children:"When he wrote this section, he had to constantly remind himself: these things happened before November. The chronological order was important."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"A certain day in August. Afternoon. The Boss walked past him."}),"\n",(0,o.jsx)(n.p,{children:"Not a meeting. No calendar invite. No invitation. No meeting room. Just walking past. He stopped for a second."}),"\n",(0,o.jsx)(n.p,{children:'"Zhaoming, got a minute? Let\'s have a quick chat."'}),"\n",(0,o.jsx)(n.p,{children:"The pantry. No one else was there. The Boss leaned against the sink, holding a cup. His tone was light. Casual. Like a post-lunch chit-chat."}),"\n",(0,o.jsx)(n.p,{children:'"I\'m telling you the truth. You know your own situation best."'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming stood there."}),"\n",(0,o.jsx)(n.p,{children:'"It\u2019s best for you if you hand in your resignation yourself before September."'}),"\n",(0,o.jsx)(n.p,{children:"The water in the cup sloshed slightly. The Boss took a sip."}),"\n",(0,o.jsx)(n.p,{children:'"I\'m speaking to you as someone who has been there. Not as your superior."'}),"\n",(0,o.jsx)(n.p,{children:"He put the cup down. His voice lowered slightly. Not hushed. But the kind of volume you only use when it's just the two of you."}),"\n",(0,o.jsx)(n.p,{children:"\"You know how small this industry is. The colleagues you've met, the people from the ODMs, the people from the vendors\u2014the circle is just this big. If you don't leave, we'll use every possible method to ruin your file. When you go out looking for a job later, and people run a background check\u2014what do you think will happen?\""}),"\n",(0,o.jsx)(n.p,{children:"The refrigerator in the pantry hummed."}),"\n",(0,o.jsx)(n.p,{children:"\"Voluntary resignation. That's best for you. I'm telling you this out of goodwill.\""}),"\n",(0,o.jsx)(n.p,{children:"The Boss's eyes were sincere. Genuine. As if he truly believed he was helping Lin Zhaoming. As if these words were the best gift he could offer."}),"\n",(0,o.jsx)(n.p,{children:"You need to leave. Leaving is for your own good. The people who stay will make sure your reputation is ruined\u2014this wasn't a threat, this was a reminder."}),"\n",(0,o.jsx)(n.p,{children:'The pantry. No recording. No email. No one else. If Lin Zhaoming went to anyone and said, "The Boss told me to resign before September"\u2014the Boss could say, "I never said such a thing. I was merely concerned about his career development."'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming looked at him."}),"\n",(0,o.jsx)(n.p,{children:'"Let me think about it."'}),"\n",(0,o.jsx)(n.p,{children:"The Boss waited a few seconds."}),"\n",(0,o.jsx)(n.p,{children:'"Don\'t think too long."'}),"\n",(0,o.jsx)(n.p,{children:"He took his cup and left."}),"\n",(0,o.jsx)(n.p,{children:"The pantry was left with only Lin Zhaoming again. The refrigerator hummed on."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"He stood there. His brain was calculating."}),"\n",(0,o.jsx)(n.p,{children:"August. Summer vacation. Looking for a job? Who was hiring? One month?"}),"\n",(0,o.jsx)(n.p,{children:"It didn't make sense."}),"\n",(0,o.jsx)(n.p,{children:"He had no savings to start over. He had family. He had daily expenses. The Hong Kong side wouldn't stop just because he lost his job."}),"\n",(0,o.jsx)(n.p,{children:"If he left on his own\u2014no severance. Nothing at all."}),"\n",(0,o.jsx)(n.p,{children:"If he didn't leave\u2014they would fire him. N+1. Not much. But he needed it."}),"\n",(0,o.jsx)(n.p,{children:"This wasn't a matter of principle. It wasn't a matter of dignity. It was math."}),"\n",(0,o.jsx)(n.p,{children:"He chose certainty."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"The days that followed."}),"\n",(0,o.jsx)(n.p,{children:"No one brought up the conversation in the pantry. No follow-up emails. No documents ever recorded those words."}),"\n",(0,o.jsx)(n.p,{children:"When the Boss saw him, he nodded, smiled, as if nothing had ever been said."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming continued to go to work. On time. Sitting in his seat. Turning on his computer."}),"\n",(0,o.jsx)(n.p,{children:"September arrived. He didn't submit a resignation letter."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"Mid-September."}),"\n",(0,o.jsx)(n.p,{children:'A meeting appeared on the calendar. Booked by the Boss. "Catch-up." Half an hour. No agenda.'}),"\n",(0,o.jsx)(n.p,{children:"When Lin Zhaoming saw that invite, his body reacted before his brain."}),"\n",(0,o.jsx)(n.p,{children:"He recognized this."}),"\n",(0,o.jsx)(n.p,{children:"He walked in."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"The same room. Not the one from last time, but the exact same size. The exact same two chairs. The exact same door closing behind them."}),"\n",(0,o.jsx)(n.p,{children:"The Boss was already sitting there."}),"\n",(0,o.jsx)(n.p,{children:'"Take a seat."'}),"\n",(0,o.jsx)(n.p,{children:"He sat down."}),"\n",(0,o.jsx)(n.p,{children:"The Boss started talking. His tone was sincere. Just like every other time."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming no longer tried to memorize what he said. Last time he tried\u2014six hours of content, and after coming out he couldn't remember anything clearly. This time he had learned. It couldn't be memorized."}),"\n",(0,o.jsx)(n.p,{children:"He only paid attention to a few things."}),"\n",(0,o.jsx)(n.p,{children:"One, the time."}),"\n",(0,o.jsx)(n.p,{children:"Two, which specific words made his heart rate change when the Boss said them."}),"\n",(0,o.jsx)(n.p,{children:"Three, whether the door had ever been opened."}),"\n",(0,o.jsx)(n.p,{children:"One hour. Two hours."}),"\n",(0,o.jsx)(n.p,{children:'The Boss\'s version was the same as last time. The same as the time before that. The same words. The same structure. "Your approach," "feedback," "I\'m doing this for your own good."'}),"\n",(0,o.jsx)(n.p,{children:"Three hours."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming's mouth was already dry. He picked up the water on the table and took a sip. The water was lukewarm. He didn't know how long it had been sitting there."}),"\n",(0,o.jsx)(n.p,{children:"Four hours."}),"\n",(0,o.jsxs)(n.p,{children:["He felt that ",(0,o.jsx)(n.em,{children:"thing"})," coming back. The same thing from last time, and the time before that. Not pain. Not fear. It was a kind of weightlessness. Like you are sitting on a normal chair, but the floor is slowly sinking. You know you are still there, but you aren't sure ",(0,o.jsx)(n.em,{children:"where"})," you are anymore."]}),"\n",(0,o.jsx)(n.p,{children:"Five hours."}),"\n",(0,o.jsx)(n.p,{children:"The Boss checked his watch."}),"\n",(0,o.jsx)(n.p,{children:'"Hold on a second."'}),"\n",(0,o.jsx)(n.p,{children:"He opened the laptop on the table. Clicked a link. Waited a few seconds."}),"\n",(0,o.jsx)(n.p,{children:"The sound of a call connecting."}),"\n",(0,o.jsx)(n.p,{children:'"Hello?" A female voice. Distant. With a slight echo. Like from another office, another floor, another world.'}),"\n",(0,o.jsx)(n.p,{children:'"Yvonne, joined. Zhaoming is here too."'}),"\n",(0,o.jsx)(n.p,{children:"The Boss's voice completely changed."}),"\n",(0,o.jsx)(n.p,{children:'Lin Zhaoming sat there, hearing the shift. Like someone unfolding a piece of cloth and covering everything that happened in the previous five hours. The Boss\'s tone jumped from that\u2014that thing that trapped you, soaking upwards like rising water\u2014to another frequency entirely. Normal. Professional. "Caring for a subordinate."'}),"\n",(0,o.jsx)(n.p,{children:"A two-second switch."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming saw all of it."}),"\n",(0,o.jsx)(n.p,{children:"But the person on the other end of the line heard none of it. Because the first sentence she heard was already a performance."}),"\n",(0,o.jsx)(n.p,{children:'"Yvonne, I had a chat with Zhaoming about his career development. I think we can discuss a concrete plan."'}),"\n",(0,o.jsx)(n.p,{children:'"Okay." Yvonne\'s voice was clear. Fresh. Like someone who just joined the company, ready to get things done. "Hi Zhaoming, I\'m Yvonne, HR Business Partner. Today we mainly want to chat about your recent performance and the direction of your development plan."'}),"\n",(0,o.jsx)(n.p,{children:"Her voice came through the laptop speakers into the room. Quietly. A bit distant."}),"\n",(0,o.jsx)(n.p,{children:"She didn't know how small this room was. She didn't know if the door was open or closed. She didn't know how long Lin Zhaoming had been sitting there. She didn't know his hands were shaking under the table. She didn't know his water cup was already empty. She didn't know what time the hallway lights would switch to night mode."}),"\n",(0,o.jsx)(n.p,{children:"All she knew was: she was asked to join a call and heard a manager and an employee discussing a development plan."}),"\n",(0,o.jsx)(n.p,{children:"The Boss slid a document forward."}),"\n",(0,o.jsx)(n.p,{children:"Performance Improvement Plan."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming stared at those few words."}),"\n",(0,o.jsx)(n.p,{children:'He knew what a PIP was. Anyone who had worked in a large corporation knew what a PIP was. PIP didn\'t mean "helping you improve." PIP meant "we have already decided you are leaving, but we need documentation."'}),"\n",(0,o.jsx)(n.p,{children:"He opened it."}),"\n",(0,o.jsx)(n.p,{children:"Three objectives."}),"\n",(0,o.jsx)(n.p,{children:'The first: "Establish a complete product line document indexing system within this quarter, covering all existing technical documents, test reports, and historical revision records."'}),"\n",(0,o.jsx)(n.p,{children:'These documents\u2014the very thing he had spent a year trying to do. Digitization. Standardized numbering. ERP integration. Every time he proposed it, every time it was blocked with "wait a minute," "now is not the right time," "no need for such a big move."'}),"\n",(0,o.jsx)(n.p,{children:"A task that couldn't be moved in a year, the PIP gave him one quarter."}),"\n",(0,o.jsx)(n.p,{children:'The second: "Proactively establish effective communication mechanisms with cross-departmental stakeholders, submitting weekly communication logs and feedback summaries."'}),"\n",(0,o.jsx)(n.p,{children:"Establishing effective communication with the people who ignored his messages. And then submitting weekly reports to prove he was communicating."}),"\n",(0,o.jsx)(n.p,{children:'The third: "Complete designated professional development courses and submit learning reflection reports."'}),"\n",(0,o.jsx)(n.p,{children:'"Effective Communication Skills," "Team Collaboration," "Self-Management."'}),"\n",(0,o.jsx)(n.p,{children:"He closed the document."}),"\n",(0,o.jsx)(n.p,{children:'"What do you think, Zhaoming?" the Boss asked.'}),"\n",(0,o.jsx)(n.p,{children:"Yvonne's voice came from the speaker: \"The purpose of this plan is to help you stay focused on development, it's not a punishment. If you have any feedback\u2014\""}),"\n",(0,o.jsx)(n.p,{children:'"Yvonne, can I record this?"'}),"\n",(0,o.jsx)(n.p,{children:"The line went silent for a moment."}),"\n",(0,o.jsx)(n.p,{children:'The Boss took over: "This is internal communication, no recording is needed. Yvonne will take notes."'}),"\n",(0,o.jsx)(n.p,{children:'Yvonne\'s voice returned: "Yes, I will take detailed meeting notes."'}),"\n",(0,o.jsx)(n.p,{children:"Her notes. On the other end of the phone. Notes covering only the version she heard."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming stared at the table."}),"\n",(0,o.jsxs)(n.p,{children:["He wanted to say: These are the things I ",(0,o.jsx)(n.em,{children:"wanted"})," to do. The things you blocked for a year. Now putting them in a PIP\u2014you don't want me to do them; you want me to fail to do them within an impossible deadline, so you have documents to say I couldn't do it."]}),"\n",(0,o.jsx)(n.p,{children:"He said none of it."}),"\n",(0,o.jsx)(n.p,{children:"Because he had already been in this room for over five hours. The residue of every single time before this\u2014the six hours, the four hours, the lunch-to-end-of-day sessions\u2014was fully present. It wasn't this single instance that broke him. It was all those previous times combined with this one."}),"\n",(0,o.jsx)(n.p,{children:"The Boss waited a beat. Then he said, \"I suggest you sign it. This isn't a penalty; it's a development plan. It's helpful for your career.\""}),"\n",(0,o.jsx)(n.p,{children:'Yvonne\'s voice: "Yes, a PIP is a supportive framework\u2014"'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming picked up the pen."}),"\n",(0,o.jsx)(n.p,{children:"Signed it."}),"\n",(0,o.jsx)(n.p,{children:"The Boss watched him. And took the document back."}),"\n",(0,o.jsx)(n.p,{children:'"Yvonne, he signed it. Please make a record."'}),"\n",(0,o.jsx)(n.p,{children:'"Got it, I\'ll send out the notes to both of you tomorrow."'}),"\n",(0,o.jsx)(n.p,{children:"The sound of typing came across the line. Clack, clack, clack. Very quiet. Very far away."}),"\n",(0,o.jsx)(n.p,{children:'"Thanks for your time. If there are any questions, you can reach out to me directly."'}),"\n",(0,o.jsx)(n.p,{children:"Clack, clack, clack."}),"\n",(0,o.jsx)(n.p,{children:"Then the call disconnected."}),"\n",(0,o.jsx)(n.p,{children:(0,o.jsx)(n.em,{children:"Beep\u2014"})}),"\n",(0,o.jsx)(n.p,{children:"The room fell silent again."}),"\n",(0,o.jsx)(n.p,{children:"The Boss stood up and patted his shoulder."}),"\n",(0,o.jsx)(n.p,{children:'"Good job. Get some good rest."'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming stood up. His legs felt weak."}),"\n",(0,o.jsx)(n.p,{children:"He walked out of that room. The hallway lights had already switched to night mode."}),"\n",(0,o.jsx)(n.p,{children:'The time Yvonne spent on the call\u2014from "joined" to hanging up\u2014was roughly fifteen minutes.'}),"\n",(0,o.jsx)(n.p,{children:"Of the five-plus hours before that, she knew nothing."}),"\n",(0,o.jsx)(n.p,{children:'If anyone checked later, the record would state: "HR participated via conference call."'}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"After the PIP was signed, the Boss walked past his desk. He paused."}),"\n",(0,o.jsx)(n.p,{children:'"Zhaoming, during the PIP period, just focus on the items in the plan. Go ahead and hand over your current projects."'}),"\n",(0,o.jsx)(n.p,{children:"Verbal. No email."}),"\n",(0,o.jsx)(n.p,{children:"The next day, people started taking over his tasks. There was no formal handover announcement. His name disappeared from the CC lists. Meeting invitations stopped arriving."}),"\n",(0,o.jsx)(n.p,{children:"His work wasn't taken away. It evaporated."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"He started working on the first PIP objective. Document indexing."}),"\n",(0,o.jsx)(n.p,{children:"He opened an Excel spreadsheet and began listing the document locations he knew of."}),"\n",(0,o.jsx)(n.p,{children:"The first drive. It contained three folders. Every folder had a different naming convention. Some used dates, some used version numbers, some used project codes. The dates had two different formats. The version numbers had three. The project codes\u2014some were legacy code bases, some were new ones, some he had never seen before in his life."}),"\n",(0,o.jsx)(n.p,{children:"He opened a report. The system said the format was unsupported. He tried another application. It opened. The data inside contradicted the data from another report. He went to find a third copy. The date on the third copy didn't align with either of the first two."}),"\n",(0,o.jsx)(n.p,{children:'Three documents. Three sets of data. Three versions. None of them were inherently "wrong"\u2014because each had a plausible context. But put the three together, and you couldn\'t find a single version that could definitively be called "right."'}),"\n",(0,o.jsx)(n.p,{children:'This was exactly the digitization process he had wanted to accomplish. The very thing he had pushed for a year, only to be stone-walled by "wait a minute."'}),"\n",(0,o.jsx)(n.p,{children:"Now these things were sitting on his desktop. Not because someone wanted him to organize them. But because someone needed him to fail."}),"\n",(0,o.jsx)(n.p,{children:"He kept working on it. Because if he didn't, he would have even less to do."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"Early October."}),"\n",(0,o.jsx)(n.p,{children:"The QTR presentation schedule was released. Quarterly Business Review. Everyone's name was on it. Including his."}),"\n",(0,o.jsx)(n.p,{children:"The Boss walked past his desk again. Using that same casual tone."}),"\n",(0,o.jsx)(n.p,{children:'"You don\'t need to attend the QTR. Just focus on your plan."'}),"\n",(0,o.jsx)(n.p,{children:"Verbal."}),"\n",(0,o.jsx)(n.p,{children:"His name was still on the calendar. If he went\u2014he wouldn't be following \"advice.\" If he didn't go\u2014the calendar explicitly stated he should be there, but he simply didn't show up."}),"\n",(0,o.jsx)(n.p,{children:'"Then who will handle my session?"'}),"\n",(0,o.jsx)(n.p,{children:"The Boss had already walked away. He didn't look back."}),"\n",(0,o.jsx)(n.p,{children:"On the day of the QTR, he sat at his desk. The door to the adjacent conference room was closed. Someone inside was presenting. He could hear the voice. Far away."}),"\n",(0,o.jsx)(n.p,{children:"He opened his computer. He worked on the document index."}),"\n",(0,o.jsx)(n.p,{children:"There was one report he clearly remembered. He had written it himself. A yield analysis for the third-generation projection module. He searched the drive for it. He couldn't find it."}),"\n",(0,o.jsx)(n.p,{children:"He tried another directory. Found a file with a similar name. Opened it."}),"\n",(0,o.jsx)(n.p,{children:"It wasn't his version. It had been altered. He remembered the specific numbers he had written down. The ones here were different. Just off by a tiny bit. Off by just enough that if you hadn't seen the original, you'd never spot the discrepancy."}),"\n",(0,o.jsx)(n.p,{children:"He had seen this kind of thing before. The incident in Chapter 8\u2014Pei-shan changing dates. Seven days."}),"\n",(0,o.jsx)(n.p,{children:"This time it wasn't seven days. It was a few percentage points."}),"\n",(0,o.jsx)(n.p,{children:"He closed the file. Moved on to the next one."}),"\n",(0,o.jsx)(n.p,{children:"The attachment for the next one wouldn't open. The link was dead."}),"\n",(0,o.jsx)(n.p,{children:"The filename of the next one was completely identical to another document, but the contents were entirely different."}),"\n",(0,o.jsx)(n.p,{children:"His Excel list grew longer and longer. Every single row represented a problem. Every problem required tracking someone down to verify. But there was no one to reach. No one replied on Teams. He walked over to people's desks, and the desks were empty\u2014hot-desking, no one knew where anyone had gone."}),"\n",(0,o.jsx)(n.p,{children:"The PIP deadline was the end of October."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"The end of October."}),"\n",(0,o.jsx)(n.p,{children:"Yvonne sent an email."}),"\n",(0,o.jsx)(n.p,{children:'"We appreciate colleague Lin Zhaoming\'s efforts during the development plan period. After review, it has been determined that certain objectives were not met within the deadline. Related records will be filed for future reference."'}),"\n",(0,o.jsx)(n.p,{children:"He finished reading it."}),"\n",(0,o.jsx)(n.p,{children:"He felt absolutely nothing."}),"\n",(0,o.jsx)(n.p,{children:"Like a faucet that has been dripping for months; one day you realize you can no longer hear it. It's not that the water stopped. It's that your ears have simply stopped processing the sound."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"November."}),"\n",(0,o.jsx)(n.p,{children:"The post-PIP Lin Zhaoming looked much the same from the outside as before."}),"\n",(0,o.jsx)(n.p,{children:"He went to work. Arrived on time. Sat down. Booted his computer. Worked on whatever tasks he had left. Submitted the reports that people still collected. Attended the meetings he was still invited to."}),"\n",(0,o.jsx)(n.p,{children:"But one thing was fundamentally different."}),"\n",(0,o.jsx)(n.p,{children:"He completely stopped reacting."}),"\n",(0,o.jsxs)(n.p,{children:["Not ",(0,o.jsx)(n.em,{children:"holding back"})," his reactions. Actually, truly, not reacting. Like a piece of rock."]}),"\n",(0,o.jsx)(n.p,{children:"Before\u2014when the Boss spoke, he would internally formulate a rebuttal. Even if he didn't voice it, his brain was churning."}),"\n",(0,o.jsx)(n.p,{children:"Now\u2014when the Boss spoke, he listened. Let him finish. No rebuttal. No formulation. No churning."}),"\n",(0,o.jsx)(n.p,{children:"Before\u2014if someone altered his reports, he would notice. He would remember. His brain would flag it."}),"\n",(0,o.jsx)(n.p,{children:"Now\u2014alter it if you want. No flags. Because what difference did a flag make anyway?"}),"\n",(0,o.jsxs)(n.p,{children:["Before\u2014during a meeting, he would analyze: ",(0,o.jsx)(n.em,{children:"Are there flaws in this proposal? Are these numbers correct?"})]}),"\n",(0,o.jsx)(n.p,{children:"Now\u2014sit. Listen. Meeting adjourned."}),"\n",(0,o.jsx)(n.p,{children:"His presence became entirely formal. An object occupying a chair. Attending without participating. Present but utterly disengaged. No emotion left to trigger. No opinions left to attack. No vulnerabilities left to exploit."}),"\n",(0,o.jsx)(n.p,{children:"The Boss tried to prod him several times."}),"\n",(0,o.jsx)(n.p,{children:'"Zhaoming, what are your thoughts?"'}),"\n",(0,o.jsx)(n.p,{children:'"No thoughts. It\'s your call."'}),"\n",(0,o.jsx)(n.p,{children:'"Are you sure you have no opinions on this?"'}),"\n",(0,o.jsx)(n.p,{children:'"None."'}),"\n",(0,o.jsx)(n.p,{children:"The Boss stared at him. He stared right back. His eyes were entirely flat. Still. Void of anger. Void of fear. Void of expectations. Void of disappointment."}),"\n",(0,o.jsx)(n.p,{children:"The Boss looked like he wanted to say something else. But there was nothing left to say. Because Lin Zhaoming had given him absolutely nothing to catch onto."}),"\n",(0,o.jsx)(n.p,{children:"You cannot argue with a stone."}),"\n",(0,o.jsx)(n.p,{children:"You cannot trap a stone in a room for seven hours. Because a stone doesn't break down."}),"\n",(0,o.jsx)(n.p,{children:"You cannot use the phrase \"I'm doing this for your own good\" on a stone. Because a stone doesn't require your goodwill."}),"\n",(0,o.jsx)(n.p,{children:"You cannot smear a stone's file. A stone doesn't have a file."}),"\n",(0,o.jsx)(n.p,{children:"Before the PIP, Lin Zhaoming was a person who reacted. Reactions created attack vectors. Attack vectors generated ammo. Ammo generated paper trails. And paper trails built the narrative."}),"\n",(0,o.jsx)(n.p,{children:"After the PIP, the ammo simply vanished."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"One day, the Boss walked past his desk. He stopped. He watched him for a while."}),"\n",(0,o.jsx)(n.p,{children:'"Are you doing okay?"'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming looked up."}),"\n",(0,o.jsx)(n.p,{children:'"I\'m fine."'}),"\n",(0,o.jsx)(n.p,{children:"There was something in the Boss's eyes. It wasn't care. It wasn't concern. It was a kind of... uncertainty. It was as if he didn't know how to process the person sitting in front of him. The previous version of Lin Zhaoming, he knew how to manage\u2014apply pressure, wait for the reaction, harvest the reaction for ammo."}),"\n",(0,o.jsx)(n.p,{children:"Now there was zero reaction."}),"\n",(0,o.jsx)(n.p,{children:"His tools had ceased to function."}),"\n",(0,o.jsx)(n.p,{children:"The Boss walked away."}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming lowered his head. He went back to work."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"He didn't remember much of the days from that period."}),"\n",(0,o.jsx)(n.p,{children:"Not because nothing happened. But because everything felt identical. Work. Tasks. Silence. Leave."}),"\n",(0,o.jsx)(n.p,{children:"What he remembered were microscopic details."}),"\n",(0,o.jsx)(n.p,{children:'He remembered eating a bento box in the pantry one afternoon while two people nearby chatted. One said, "I heard there\'s gonna be another round of layoffs over there." The other replied, "Mm." Then silence. They both kept eating.'}),"\n",(0,o.jsx)(n.p,{children:"He remembered a day it rained heavily. He hadn't brought an umbrella. He stood at the company entrance, waiting. The rain poured. He stood there for ten minutes. He didn't think about anything. Just stood there. Watching the rain."}),"\n",(0,o.jsx)(n.p,{children:"He remembered coming home one evening, and his wife asked if he had eaten. He said he had. He hadn't."}),"\n",(0,o.jsx)(n.p,{children:"These were the things he remembered."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"And then came the team building event."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"Study room."}),"\n",(0,o.jsx)(n.p,{children:"He put down his pen."}),"\n",(0,o.jsx)(n.p,{children:"The day he signed the PIP\u2014the first five hours alone with the Boss, and the final fifteen minutes when Yvonne's voice joined the call\u2014he could now perfectly recall its entirety. But when he walked out of that room that day, he had only remembered a sensation. Not pain. Not rage. Emptiness. Like someone had opened his skull, removed several components, and secured the lid back on. He didn't know what was missing. He just knew it was gone."}),"\n",(0,o.jsx)(n.p,{children:"He honestly didn't know if the Boss had specifically waited for him to cognitively collapse before presenting the PIP. He wasn't certain."}),"\n",(0,o.jsx)(n.p,{children:"But for a Boss to drop everything and confine someone to a room for seven hours\u2014that scale of time investment wasn't random."}),"\n",(0,o.jsxs)(n.p,{children:["That was a deduction. He didn't ",(0,o.jsx)(n.em,{children:"know"})," it for a fact."]}),"\n",(0,o.jsx)(n.p,{children:"What he did know was: all the most critical maneuvers were verbal."}),"\n",(0,o.jsx)(n.p,{children:"The pantry suggestion to resign\u2014verbal. The instruction not to attend the QTR\u2014verbal. The directive to hand over his projects\u2014verbal."}),"\n",(0,o.jsx)(n.p,{children:'On paper, absolutely nothing had happened. On the calendar, he was a completely standard employee. The PIP had his signature on it, given voluntarily. Yvonne\'s notes documented a "constructive dialogue." If he ever raised a formal complaint, the corporate narrative would be ironclad: a caring manager trying to guide an underperforming employee who struggled with communication.'}),"\n",(0,o.jsx)(n.p,{children:"Yvonne was on the phone for exactly fifteen minutes. She didn't turn on her camera. She had never seen Lin Zhaoming's face during that meeting. She didn't know the dimensions of the room. Didn't know if the door was sealed. Didn't know if Lin Zhaoming's hands were trembling beneath the table. All she heard was a manager expressing deep concern while discussing a development plan with his subordinate."}),"\n",(0,o.jsx)(n.p,{children:"That was her entire reality of the event."}),"\n",(0,o.jsx)(n.p,{children:'If there ever came a day when someone inevitably asked Yvonne, "Did you witness any inappropriate conduct?"'}),"\n",(0,o.jsx)(n.p,{children:'She would respond with absolute sincerity: "No. The atmosphere of communication was excellent. The employee signed the document voluntarily."'}),"\n",(0,o.jsx)(n.p,{children:"She wouldn't be lying. She would truthfully report everything she heard. And what she heard was entirely segregated from reality."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"And after orchestrating all of that, the final severance package was standard statutory compensation. Exactly identical to a straight termination."}),"\n",(0,o.jsxs)(n.p,{children:["Which meant\u2014none of those maneuvers were actually about ",(0,o.jsx)(n.em,{children:"firing"})," him. You don't need a complex reason to fire someone. You just pay out the severance."]}),"\n",(0,o.jsx)(n.p,{children:"Those maneuvers were designed for the aftermath."}),"\n",(0,o.jsx)(n.p,{children:'For what the paper trail would reflect. For establishing the corporate narrative in case he filed a grievance. The remaining employees watched him be processed into a "narrative" before disappearing\u2014they learned the lesson clearly: an uncooperative employee gets attached to a very specific kind of story.'}),"\n",(0,o.jsx)(n.p,{children:"The chaos he originally wanted to fix had been reverse-engineered into the tool to punish him. The digital standardization he pushed for a year, which no one cared about, was surgically adapted into a PIP objective he couldn't possibly achieve in one quarter."}),"\n",(0,o.jsx)(n.p,{children:"And on the day he signed the PIP, he firmly believed he had completely lost."}),"\n",(0,o.jsx)(n.p,{children:"It was only later that he slowly realized the truth: He wasn't the one who lost. That was simply their very last card to play. Because he had abruptly stopped reacting. He stopped supplying them with anything they could use."}),"\n",(0,o.jsx)(n.p,{children:"\"Grey Rock\" wasn't a deliberate strategy on his part. It wasn't a tactical countermeasure he plotted out on a whiteboard."}),"\n",(0,o.jsx)(n.p,{children:"It was the biological default state of someone who had been beaten down to the point where there was absolutely nowhere left to hit."}),"\n",(0,o.jsx)(n.p,{children:"It merely happened to be the one state immune to attack."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:"That night."}),"\n",(0,o.jsx)(n.p,{children:"He returned home. His wife was in the living room."}),"\n",(0,o.jsx)(n.p,{children:"He changed his shoes. Sat down."}),"\n",(0,o.jsx)(n.p,{children:'"Did you eat yet?"'}),"\n",(0,o.jsx)(n.p,{children:'"No."'}),"\n",(0,o.jsx)(n.p,{children:"His wife went to cook something. He sat on the sofa. The TV was on. He wasn't watching it."}),"\n",(0,o.jsx)(n.p,{children:"His wife brought out a bowl of noodles. She sat down next to him."}),"\n",(0,o.jsx)(n.p,{children:'"That... that plan you were doing... is it over?"'}),"\n",(0,o.jsx)(n.p,{children:"His wife knew the PIP existed. He hadn't shared the mechanics of it. He only told her: there was a plan he had to execute. Once it was done, they'd know where things stood."}),"\n",(0,o.jsx)(n.p,{children:'"It\'s over."'}),"\n",(0,o.jsx)(n.p,{children:'"And the result?"'}),"\n",(0,o.jsx)(n.p,{children:'"As expected."'}),"\n",(0,o.jsx)(n.p,{children:"His wife looked at him."}),"\n",(0,o.jsx)(n.p,{children:'"So... what do we do now?"'}),"\n",(0,o.jsx)(n.p,{children:"Lin Zhaoming ate his noodles."}),"\n",(0,o.jsx)(n.p,{children:'"We wait. They will do what they need to do."'}),"\n",(0,o.jsx)(n.p,{children:'"Aren\'t you going to do something about it?"'}),"\n",(0,o.jsx)(n.p,{children:'"There\'s nothing left to do."'}),"\n",(0,o.jsx)(n.p,{children:"His wife didn't press the issue."}),"\n",(0,o.jsx)(n.p,{children:"They sat there together. The TV volume was low."}),"\n",(0,o.jsx)(n.p,{children:"He finished the noodles. Put down the bowl."}),"\n",(0,o.jsx)(n.p,{children:'"Thank you."'}),"\n",(0,o.jsx)(n.p,{children:"His wife took the bowl into the kitchen. He sat alone in the living room."}),"\n",(0,o.jsx)(n.p,{children:"Outside the window was the Taipei night. Late October. It was starting to get cold."}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.p,{children:(0,o.jsx)(n.strong,{children:"Key Highlights:"})}),"\n",(0,o.jsxs)(n.blockquote,{children:["\n",(0,o.jsx)(n.p,{children:"\"Forcing a resignation in the pantry\u2014no calendar invite, no meeting room, no email\u2014the Boss can deny it at any time. Out of the seven-hour PIP ordeal, HR only joined via a fifteen-minute call\u2014no video, having never seen Lin Zhaoming's face. The very first sentence she hears is already a performance\u2014because the Boss switched his frequency precisely two seconds before the call connected. Lin Zhaoming witnesses this entire switch. But the person on the other end hears nothing. Orally stripping away work, orally blocking attendance at the QTR\u2014on paper, nothing happened. On the calendar, he remains a perfectly normal employee. If he files a complaint: 'He chose not to attend the QTR himself; no one stopped him. He signed the PIP voluntarily. HR was present the entire time. The communication was highly constructive.' Every single statement is technically true. But woven together, they fabricate an entirely different narrative. Yvonne isn't the villain. Everything she executes is fully compliant with procedure. But her functional purpose isn't 'witnessing'\u2014it's solely so the paper trail can bear the sentence 'HR participated.' The 'no video' detail crystalizes this layer: she doesn't even qualify as a 'witness.' She was merely an 'auditor.' And the fifteen minutes she heard existed in an entirely different dimension from the agonizing seven hours of reality. The final line, 'And then came the team building event'\u2014the reader has already read Chapter 16. The KTV session during the grey rock period. All those verbal barbs landing harmlessly against a literal stone.\""}),"\n"]})]})}function c(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>a,x:()=>h});var o=t(6540);const i={},s=o.createContext(i);function a(e){const n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function h(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);